    fun generateWalletAuthToken(userId: String, ttlMs: Long = 10 * 60 * 1000L): String {
        val now = SystemClock.elapsedRealtime()
        val exp = now + ttlMs
        val nonce = UUID.randomUUID().toString()

        val secretKey = ensureDeviceSecretKey()
        val payload = JSONObject()
            .put("v", 1)
            .put("u", userId)
            .put("n", nonce)
            .put("exp", exp)
            .put("sdk", Build.VERSION.SDK_INT)
            .toString()

        val sig = hmacSha256(secretKey, payload.toByteArray(Charsets.UTF_8))
        val tokenObj = JSONObject()
            .put("p", Base64.encodeToString(payload.toByteArray(Charsets.UTF_8), Base64.NO_WRAP))
            .put("s", Base64.encodeToString(sig, Base64.NO_WRAP))
            .toString()

        return Base64.encodeToString(tokenObj.toByteArray(Charsets.UTF_8), Base64.NO_WRAP)
    }

