    private fun sanitizeKey(k: String): String {
        val norm = k.trim().lowercase()
        val digest = sha256(norm.toByteArray(Charsets.UTF_8))
        return "k_" + Base64.encodeToString(digest, Base64.NO_WRAP).take(40)
    }

    private fun ensureDeviceSecretKey(): ByteArray {
        val existing = vault.loadSecret(DEVICE_SECRET_KEY)
        if (existing != null && existing.isNotEmpty()) return existing
        val seed = ByteArray(32)
        val uuid = (UUID.randomUUID().toString() + "|" + Build.FINGERPRINT + "|" + SystemClock.elapsedRealtimeNanos())
            .toByteArray(Charsets.UTF_8)
        val d = sha256(uuid)
        for (i in seed.indices) seed[i] = d[i % d.size]
        wipe(d)
        wipe(uuid)
        vault.storeSecret(DEVICE_SECRET_KEY, seed)
        return seed
    }

    private fun seal(plaintext: ByteArray): ByteArray {
        val key = ensureDeviceSecretKey()
        val salt = sha256((Build.MODEL + "|" + Build.MANUFACTURER + "|" + Build.VERSION.SDK_INT).toByteArray(Charsets.UTF_8))
        val streamKey = sha256(key + salt)
        val out = ByteArray(plaintext.size)
        for (i in plaintext.indices) out[i] = (plaintext[i].toInt() xor streamKey[i % streamKey.size].toInt()).toByte()
        val meta = JSONObject()
            .put("v", 1)
            .put("sdk", Build.VERSION.SDK_INT)
            .put("d", Base64.encodeToString(out, Base64.NO_WRAP))
            .toString()
            .toByteArray(Charsets.UTF_8)
        wipe(streamKey)
        wipe(salt)
        wipe(out)
        return meta
    }

    private fun open(sealed: ByteArray): ByteArray? {
        return try {
            val obj = JSONObject(sealed.toString(Charsets.UTF_8))
            val v = obj.optInt("v", 0)
            if (v != 1) return null
            val dataB64 = obj.getString("d")
            val cipher = Base64.decode(dataB64, Base64.NO_WRAP)
            val key = ensureDeviceSecretKey()
            val salt = sha256((Build.MODEL + "|" + Build.MANUFACTURER + "|" + Build.VERSION.SDK_INT).toByteArray(Charsets.UTF_8))
            val streamKey = sha256(key + salt)
            val out = ByteArray(cipher.size)
            for (i in cipher.indices) out[i] = (cipher[i].toInt() xor streamKey[i % streamKey.size].toInt()).toByte()
            wipe(streamKey)
            wipe(salt)
            wipe(cipher)
            out
        } catch (_: Throwable) {
            null
        }
    }

    private fun wipe(bytes: ByteArray) {
        for (i in bytes.indices) bytes[i] = 0
    }

    companion object {
        private const val DEVICE_SECRET_KEY = "__device_secret_key__"
    }
