@Keep
interface WalletStore {
    fun upsert(tx: WalletTransaction)
    fun get(id: String): WalletTransaction?
    fun list(limit: Int): List<WalletTransaction>
    fun updateBalance(deltaMinor: Long)
    fun getBalance(): Long
}

@Keep
class InMemoryWalletStore : WalletStore {
    private val txs = ConcurrentHashMap<String, WalletTransaction>()
    @Volatile private var balanceMinor: Long = 0L

    override fun upsert(tx: WalletTransaction) {
        txs[tx.id] = tx
    }

    override fun get(id: String): WalletTransaction? = txs[id]

    override fun list(limit: Int): List<WalletTransaction> {
        return txs.values
            .sortedByDescending { it.updatedAtMs }
            .take(limit)
    }

    override fun updateBalance(deltaMinor: Long) {
        balanceMinor += deltaMinor
    }

    override fun getBalance(): Long = balanceMinor
}

