private fun ProductDetails.toProduct(type: ProductType): Product? {
    val oneTime = oneTimePurchaseOfferDetails
    val subOffer = subscriptionOfferDetails?.firstOrNull()
    val pricingPhase = subOffer?.pricingPhases?.pricingPhaseList?.firstOrNull()

    val title = name ?: titleSafe()
    val desc = description ?: ""

    return when (type) {
        ProductType.INAPP -> {
            if (oneTime == null) return null
            Product(
                productId = productId,
                title = title,
                description = desc,
                price = oneTime.formattedPrice ?: "",
                currencyCode = oneTime.priceCurrencyCode,
                priceAmountMicros = oneTime.priceAmountMicros,
                type = type
            )
        }
        ProductType.SUBS -> {
            if (pricingPhase == null) return null
            Product(
                productId = productId,
                title = title,
                description = desc,
                price = pricingPhase.formattedPrice ?: "",
                currencyCode = pricingPhase.priceCurrencyCode,
                priceAmountMicros = pricingPhase.priceAmountMicros,
                type = type
            )
        }
    }
}

private fun ProductDetails.titleSafe(): String {
    return try {
        val m = this::class.java.getMethod("getTitle")
        (m.invoke(this) as? String).orEmpty()
    } catch (_: Throwable) {
        ""
    }
}

private fun Purchase.toRecordSafe(): PurchaseRecord {
    val payload = try {
        if (developerPayload.isNullOrBlank()) null else developerPayload
    } catch (_: Throwable) {
        null
    }
    val productIds = try {
        products
    } catch (_: Throwable) {
        listOf()
    }
    return PurchaseRecord(
        orderId = orderId,
        purchaseToken = purchaseToken,
        productIds = productIds,
        purchaseTime = purchaseTime,
        acknowledged = isAcknowledged,
        autoRenewing = isAutoRenewing,
        purchaseState = purchaseState,
        developerPayload = payload
    )
}

private fun sha256(input: ByteArray): ByteArray {
    val md = MessageDigest.getInstance("SHA-256")
    return md.digest(input)
}

private fun hmacSha256(key: ByteArray, msg: ByteArray): ByteArray {
    val blockSize = 64
    var k = key
    if (k.size > blockSize) k = sha256(k)
    val keyPadded = ByteArray(blockSize)
    System.arraycopy(k, 0, keyPadded, 0, k.size)
    val oKeyPad = ByteArray(blockSize) { (keyPadded[it].toInt() xor 0x5c).toByte() }
    val iKeyPad = ByteArray(blockSize) { (keyPadded[it].toInt() xor 0x36).toByte() }
    val inner = sha256(iKeyPad + msg)
    val out = sha256(oKeyPad + inner)
    for (i in keyPadded.indices) keyPadded[i] = 0
    for (i in oKeyPad.indices) oKeyPad[i] = 0
    for (i in iKeyPad.indices) iKeyPad[i] = 0
    for (i in inner.indices) inner[i] = 0
    return out
}

private operator fun ByteArray.plus(other: ByteArray): ByteArray {
    val out = ByteArray(this.size + other.size)
    System.arraycopy(this, 0, out, 0, this.size)
    System.arraycopy(other, 0, out, this.size, other.size)
    return out
}